package com.example.medibloomappv2.data.remote;

import com.example.medibloomappv2.data.remote.model.GeminiRequest;
import com.example.medibloomappv2.data.remote.model.GeminiResponse;

import retrofit2.Call;
import retrofit2.http.Body;
import retrofit2.http.POST;
import retrofit2.http.Query;

public interface GeminiApiService {

    @POST("v1beta/models/gemini-2.0-flash:generateContent")
    Call<GeminiResponse> generateContent(
            @Query("key") String apiKey,
            @Body GeminiRequest request
    );
}

package com.example.medibloomappv2.data.remote;

import com.example.medibloomappv2.data.remote.model.GeminiRequest;
import com.example.medibloomappv2.data.remote.model.GeminiResponse;

import retrofit2.Call;
import retrofit2.http.Body;
import retrofit2.http.POST;
import retrofit2.http.Query;

public interface GeminiApiService {

    // gemini-2.0-flash-001 = stable pinned version (avoids silent model deprecations)
    @POST("v1beta/models/gemini-2.0-flash-001:generateContent")
    Call<GeminiResponse> generateContent(
            @Query("key") String apiKey,
            @Body GeminiRequest request
    );
}

package com.example.medibloomappv2.data.remote.model;

import java.util.List;

public class GeminiRequest {
    public List<Content> contents;
    public SystemInstruction system_instruction;

    public GeminiRequest(List<Content> contents, SystemInstruction systemInstruction) {
        this.contents = contents;
        this.system_instruction = systemInstruction;
    }

    public static class Content {
        public String role; // "user" or "model"
        public List<Part> parts;

        public Content(String role, String text) {
            this.role = role;
            this.parts = List.of(new Part(text));
        }
    }

    public static class Part {
        public String text;

        public Part(String text) {
            this.text = text;
        }
    }

    public static class SystemInstruction {
        public List<Part> parts;

        public SystemInstruction(String text) {
            this.parts = List.of(new Part(text));
        }
    }
}

package com.example.medibloomappv2.data.remote.model;

import java.util.Collections;
import java.util.List;

public class GeminiRequest {
    public List<Content> contents;
    public SystemInstruction system_instruction;

    public GeminiRequest(List<Content> contents, SystemInstruction systemInstruction) {
        this.contents = contents;
        this.system_instruction = systemInstruction;
    }

    public static class Content {
        public String role; // "user" or "model"
        public List<Part> parts;

        public Content(String role, String text) {
            this.role = role;
            this.parts = Collections.singletonList(new Part(text));
        }
    }

    public static class Part {
        public String text;

        public Part(String text) {
            this.text = text;
        }
    }

    public static class SystemInstruction {
        public List<Part> parts;

        public SystemInstruction(String text) {
            this.parts = Collections.singletonList(new Part(text));
        }
    }
}

package com.example.medibloomappv2.data.repository;

import android.util.Log;

import androidx.lifecycle.MutableLiveData;

import com.example.medibloomappv2.BuildConfig;
import com.example.medibloomappv2.data.remote.RetrofitClient;
import com.example.medibloomappv2.data.remote.model.GeminiRequest;
import com.example.medibloomappv2.data.remote.model.GeminiResponse;

import java.util.ArrayList;
import java.util.List;

import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;

public class GeminiRepository {

    private static final String TAG = "GeminiRepository";
    private final List<GeminiRequest.Content> conversationHistory = new ArrayList<>();
    private final String medicineContext;

    public GeminiRepository(String medicineContext) {
        this.medicineContext = medicineContext;
    }

    public void sendMessage(String userMessage, MutableLiveData<String> responseLiveData,
                            MutableLiveData<Boolean> loadingLiveData,
                            MutableLiveData<String> errorLiveData) {

        conversationHistory.add(new GeminiRequest.Content("user", userMessage));
        loadingLiveData.postValue(true);

        String systemPrompt = "You are MediBloom Assistant, a friendly and empathetic health companion app. "
                + "You help users understand general information about medications, build healthy habits, "
                + "and manage their medicine routines. Always be warm, supportive, and use emojis occasionally. "
                + "IMPORTANT: Only provide general health information, never personalized medical advice. "
                + "Always recommend consulting a doctor for medical concerns. "
                + "The user currently has these medicines registered: " + medicineContext + ". "
                + "Keep responses concise and easy to understand.";

        GeminiRequest request = new GeminiRequest(
                new ArrayList<>(conversationHistory),
                new GeminiRequest.SystemInstruction(systemPrompt)
        );

        RetrofitClient.getInstance().getGeminiApiService()
                .generateContent(BuildConfig.GEMINI_API_KEY, request)
                .enqueue(new Callback<GeminiResponse>() {
                    @Override
                    public void onResponse(Call<GeminiResponse> call, Response<GeminiResponse> response) {
                        loadingLiveData.postValue(false);
                        if (response.isSuccessful() && response.body() != null) {
                            String text = response.body().getText();
                            if (!text.isEmpty()) {
                                conversationHistory.add(new GeminiRequest.Content("model", text));
                                responseLiveData.postValue(text);
                            } else {
                                errorLiveData.postValue("Empty response from AI.");
                            }
                        } else {
                            Log.e(TAG, "API error: " + response.code());
                            errorLiveData.postValue("AI service error. Please try again.");
                        }
                    }

                    @Override
                    public void onFailure(Call<GeminiResponse> call, Throwable t) {
                        loadingLiveData.postValue(false);
                        Log.e(TAG, "Network failure: " + t.getMessage());
                        errorLiveData.postValue("Network error. Please check your connection.");
                    }
                });
    }

    public void clearHistory() {
        conversationHistory.clear();
    }
}

package com.example.medibloomappv2.data.repository;

import android.util.Log;

import androidx.lifecycle.MutableLiveData;

import com.example.medibloomappv2.BuildConfig;
import com.example.medibloomappv2.data.remote.RetrofitClient;
import com.example.medibloomappv2.data.remote.model.GeminiRequest;
import com.example.medibloomappv2.data.remote.model.GeminiResponse;

import java.io.IOException;
import java.util.ArrayList;
import java.util.List;

import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;

public class GeminiRepository {

    private static final String TAG = "GeminiRepository";
    private final List<GeminiRequest.Content> conversationHistory = new ArrayList<>();
    private final String medicineContext;

    public GeminiRepository(String medicineContext) {
        this.medicineContext = medicineContext;
    }

    public void sendMessage(String userMessage,
                            MutableLiveData<String> responseLiveData,
                            MutableLiveData<Boolean> loadingLiveData,
                            MutableLiveData<String> errorLiveData) {

        conversationHistory.add(new GeminiRequest.Content("user", userMessage));
        loadingLiveData.postValue(true);

        String systemPrompt = "You are MediBloom Assistant, a friendly and empathetic health companion. "
                + "You help users understand general information about medications, build healthy habits, "
                + "and manage their medicine routines. Always be warm, supportive, and use emojis occasionally. "
                + "IMPORTANT: Only provide general health information, never personalised medical advice. "
                + "Always recommend consulting a doctor for medical concerns. "
                + "The user currently has these medicines registered: " + medicineContext + ". "
                + "Keep responses concise and easy to understand.";

        GeminiRequest request = new GeminiRequest(
                new ArrayList<>(conversationHistory),
                new GeminiRequest.SystemInstruction(systemPrompt)
        );

        // Verify the key is not empty before making the call
        if (BuildConfig.GEMINI_API_KEY == null || BuildConfig.GEMINI_API_KEY.isEmpty()) {
            loadingLiveData.postValue(false);
            errorLiveData.postValue("Gemini API key is missing. Please add it to local.properties.");
            return;
        }

        RetrofitClient.getInstance().getGeminiApiService()
                .generateContent(BuildConfig.GEMINI_API_KEY, request)
                .enqueue(new Callback<GeminiResponse>() {
                    @Override
                    public void onResponse(Call<GeminiResponse> call, Response<GeminiResponse> response) {
                        loadingLiveData.postValue(false);

                        if (response.isSuccessful() && response.body() != null) {
                            String text = response.body().getText();
                            if (text != null && !text.isEmpty()) {
                                conversationHistory.add(new GeminiRequest.Content("model", text));
                                responseLiveData.postValue(text);
                            } else {
                                // Response was blocked or empty – remove the user message from history
                                if (!conversationHistory.isEmpty())
                                    conversationHistory.remove(conversationHistory.size() - 1);
                                errorLiveData.postValue("The assistant couldn't generate a response. Please try rephrasing.");
                            }
                        } else {
                            // Read the actual error body so we know what went wrong
                            String errorBody = "";
                            try {
                                if (response.errorBody() != null) {
                                    errorBody = response.errorBody().string();
                                }
                            } catch (IOException e) {
                                Log.e(TAG, "Could not read error body", e);
                            }

                            Log.e(TAG, "API error " + response.code() + ": " + errorBody);

                            // Remove the failed user message from history so retry works
                            if (!conversationHistory.isEmpty())
                                conversationHistory.remove(conversationHistory.size() - 1);

                            // Show a specific, helpful message based on the HTTP status code
                            String userMessage2 = errorMessageFor(response.code(), errorBody);
                            errorLiveData.postValue(userMessage2);
                        }
                    }

                    @Override
                    public void onFailure(Call<GeminiResponse> call, Throwable t) {
                        loadingLiveData.postValue(false);
                        if (!conversationHistory.isEmpty())
                            conversationHistory.remove(conversationHistory.size() - 1);
                        Log.e(TAG, "Network failure: " + t.getMessage(), t);
                        errorLiveData.postValue("Network error. Please check your internet connection and try again.");
                    }
                });
    }

    /** Returns a user-friendly error string based on HTTP status code and raw error body. */
    private String errorMessageFor(int code, String body) {
        switch (code) {
            case 400:
                if (body.contains("API_KEY_INVALID") || body.contains("invalid"))
                    return "Your Gemini API key is invalid. Please check local.properties.";
                return "Bad request sent to the AI service. Please try again.";
            case 401:
                return "Authentication failed. Please check your Gemini API key.";
            case 403:
                if (body.contains("API_KEY_INVALID"))
                    return "Your Gemini API key is invalid or has been revoked.";
                if (body.contains("PERMISSION_DENIED"))
                    return "This API key does not have permission to use Gemini. Enable it at aistudio.google.com.";
                return "Access denied. Please check your Gemini API key.";
            case 404:
                return "AI model not found. Please check the model name in GeminiApiService.";
            case 429:
                return "You've hit the free quota limit. Please wait a moment and try again.";
            case 500:
            case 503:
                return "Google's AI service is temporarily unavailable. Please try again later.";
            default:
                return "AI service error (" + code + "). Please try again.";
        }
    }

    public void clearHistory() {
        conversationHistory.clear();
    }
}

package com.example.medibloomappv2.ui.assistant;

import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.EditText;
import android.widget.HorizontalScrollView;
import android.widget.LinearLayout;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;
import androidx.lifecycle.ViewModelProvider;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.airbnb.lottie.LottieAnimationView;
import com.example.medibloomappv2.R;
import com.example.medibloomappv2.domain.model.ChatMessage;
import com.google.android.material.chip.Chip;
import com.google.android.material.floatingactionbutton.FloatingActionButton;

import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.Locale;

public class AssistantFragment extends Fragment {

    private AssistantViewModel viewModel;
    private ChatAdapter chatAdapter;
    private RecyclerView rvChat;
    private EditText etMessage;
    private FloatingActionButton fabSend;
    private LottieAnimationView lottieTyping;
    private LinearLayout chipContainer;

    private final String[] suggestions = {
            "What is my medicine used for?",
            "Common side effects",
            "How can I improve my reminder habit?",
            "What should I eat while taking medicine?",
            "Explain my medicine schedule"
    };

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container,
                             @Nullable Bundle savedInstanceState) {
        return inflater.inflate(R.layout.fragment_assistant, container, false);
    }

    @Override
    public void onViewCreated(@NonNull View view, @Nullable Bundle savedInstanceState) {
        super.onViewCreated(view, savedInstanceState);

        viewModel = new ViewModelProvider(this).get(AssistantViewModel.class);
        viewModel.init(requireContext());

        rvChat = view.findViewById(R.id.rv_chat);
        etMessage = view.findViewById(R.id.et_message);
        fabSend = view.findViewById(R.id.fab_send);
        lottieTyping = view.findViewById(R.id.lottie_typing);
        chipContainer = view.findViewById(R.id.chip_container);

        LinearLayoutManager llm = new LinearLayoutManager(requireContext());
        llm.setStackFromEnd(true);
        rvChat.setLayoutManager(llm);
        chatAdapter = new ChatAdapter();
        rvChat.setAdapter(chatAdapter);

        // Suggestion chips
        for (String s : suggestions) {
            Chip chip = new Chip(requireContext());
            chip.setText(s);
            chip.setCheckable(false);
            chip.setChipBackgroundColorResource(R.color.chip_suggestion_bg);
            chip.setTextColor(requireContext().getColor(R.color.text_primary));
            chip.setOnClickListener(v -> sendMessage(s));
            chipContainer.addView(chip);
        }

        fabSend.setOnClickListener(v -> {
            String text = etMessage.getText().toString().trim();
            if (!text.isEmpty()) {
                sendMessage(text);
                etMessage.setText("");
            }
        });

        // Observe messages
        viewModel.getMessages().observe(getViewLifecycleOwner(), messages -> {
            chatAdapter.submitList(messages);
            rvChat.smoothScrollToPosition(Math.max(0, messages.size() - 1));
        });

        // Observe typing
        viewModel.getIsTyping().observe(getViewLifecycleOwner(), typing -> {
            lottieTyping.setVisibility(typing ? View.VISIBLE : View.GONE);
            if (typing) lottieTyping.playAnimation();
        });

        // Observe errors
        viewModel.getError().observe(getViewLifecycleOwner(), error -> {
            if (error != null && !error.isEmpty()) {
                Toast.makeText(requireContext(), error, Toast.LENGTH_LONG).show();
            }
        });
    }

    private void sendMessage(String text) {
        String time = new SimpleDateFormat("hh:mm a", Locale.getDefault()).format(new Date());
        viewModel.sendMessage(text, time);
    }
}

package com.example.medibloomappv2.ui.assistant;

import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.EditText;
import android.widget.LinearLayout;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;
import androidx.lifecycle.ViewModelProvider;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.airbnb.lottie.LottieAnimationView;
import com.example.medibloomappv2.R;
import com.example.medibloomappv2.domain.model.ChatMessage;
import com.google.android.material.chip.Chip;

import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.Locale;

public class AssistantFragment extends Fragment {

    private AssistantViewModel viewModel;
    private ChatAdapter chatAdapter;
    private RecyclerView rvChat;
    private EditText etMessage;
    private View fabSend;               // now a FrameLayout in the layout
    private LottieAnimationView lottieTyping;
    private LinearLayout layoutTyping; // outer wrapper (shown/hidden together)
    private LinearLayout chipContainer;

    private final String[] suggestions = {
            "What is my medicine used for?",
            "Common side effects",
            "How can I improve my reminder habit?",
            "What should I eat while taking medicine?",
            "Explain my medicine schedule"
    };

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container,
                             @Nullable Bundle savedInstanceState) {
        return inflater.inflate(R.layout.fragment_assistant, container, false);
    }

    @Override
    public void onViewCreated(@NonNull View view, @Nullable Bundle savedInstanceState) {
        super.onViewCreated(view, savedInstanceState);

        viewModel = new ViewModelProvider(this).get(AssistantViewModel.class);
        viewModel.init(requireContext());

        rvChat        = view.findViewById(R.id.rv_chat);
        etMessage     = view.findViewById(R.id.et_message);
        fabSend       = view.findViewById(R.id.fab_send);
        lottieTyping  = view.findViewById(R.id.lottie_typing);
        layoutTyping  = view.findViewById(R.id.layout_typing);
        chipContainer = view.findViewById(R.id.chip_container);

        LinearLayoutManager llm = new LinearLayoutManager(requireContext());
        llm.setStackFromEnd(true);
        rvChat.setLayoutManager(llm);
        chatAdapter = new ChatAdapter();
        rvChat.setAdapter(chatAdapter);

        // ── Suggestion chips ──────────────────────────────────────
        for (String s : suggestions) {
            Chip chip = new Chip(requireContext());
            chip.setText(s);
            chip.setCheckable(false);
            chip.setChipBackgroundColorResource(R.color.chip_suggestion_bg);
            chip.setTextColor(requireContext().getColor(R.color.text_primary));
            chip.setOnClickListener(v -> sendMessage(s));
            chipContainer.addView(chip);
        }

        // ── Send button ───────────────────────────────────────────
        fabSend.setOnClickListener(v -> {
            String text = etMessage.getText().toString().trim();
            if (!text.isEmpty()) {
                sendMessage(text);
                etMessage.setText("");
            }
        });

        // ── Also send on keyboard "Send" action ───────────────────
        etMessage.setOnEditorActionListener((tv, actionId, event) -> {
            String text = etMessage.getText().toString().trim();
            if (!text.isEmpty()) {
                sendMessage(text);
                etMessage.setText("");
                return true;
            }
            return false;
        });

        // ── Observe messages ──────────────────────────────────────
        viewModel.getMessages().observe(getViewLifecycleOwner(), messages -> {
            chatAdapter.submitList(messages);
            if (!messages.isEmpty()) {
                rvChat.smoothScrollToPosition(messages.size() - 1);
            }
        });

        // ── Observe typing indicator ──────────────────────────────
        viewModel.getIsTyping().observe(getViewLifecycleOwner(), typing -> {
            if (layoutTyping == null) return;
            layoutTyping.setVisibility(typing ? View.VISIBLE : View.GONE);
            if (typing) lottieTyping.playAnimation();
        });

        // ── Observe errors ────────────────────────────────────────
        viewModel.getError().observe(getViewLifecycleOwner(), error -> {
            if (error != null && !error.isEmpty()) {
                Toast.makeText(requireContext(), "❌ " + error, Toast.LENGTH_LONG).show();
            }
        });
    }

    private void sendMessage(String text) {
        String time = new SimpleDateFormat("hh:mm a", Locale.getDefault()).format(new Date());
        viewModel.sendMessage(text, time);
    }
}

package com.example.medibloomappv2.ui.auth;

import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.example.medibloomappv2.R;
import com.example.medibloomappv2.data.repository.AuthRepository;
import com.example.medibloomappv2.ui.main.MainActivity;
import com.example.medibloomappv2.utils.PreferenceManager;
import com.google.android.material.button.MaterialButton;
import com.google.android.material.progressindicator.CircularProgressIndicator;
import com.google.android.material.textfield.TextInputEditText;

public class LoginActivity extends AppCompatActivity {

    private TextInputEditText etEmail, etPassword;
    private MaterialButton btnLogin;
    private CircularProgressIndicator progressIndicator;
    private AuthRepository authRepository;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        authRepository = new AuthRepository(this);

        etEmail = findViewById(R.id.et_email);
        etPassword = findViewById(R.id.et_password);
        btnLogin = findViewById(R.id.btn_login);
        progressIndicator = findViewById(R.id.progress_indicator);
        TextView tvForgotPassword = findViewById(R.id.tv_forgot_password);
        TextView tvSignUp = findViewById(R.id.tv_sign_up);

        btnLogin.setOnClickListener(v -> attemptLogin());

        tvForgotPassword.setOnClickListener(v -> {
            startActivity(new Intent(this, ForgotPasswordActivity.class));
            overridePendingTransition(android.R.anim.slide_in_left, android.R.anim.slide_out_right);
        });

        tvSignUp.setOnClickListener(v -> {
            startActivity(new Intent(this, SignUpActivity.class));
            overridePendingTransition(android.R.anim.slide_in_left, android.R.anim.slide_out_right);
        });
    }

    private void attemptLogin() {
        String email = getFieldText(etEmail);
        String password = getFieldText(etPassword);

        if (email.isEmpty()) { etEmail.setError("Email is required"); etEmail.requestFocus(); return; }
        if (password.isEmpty()) { etPassword.setError("Password is required"); etPassword.requestFocus(); return; }
        if (password.length() < 6) { etPassword.setError("Minimum 6 characters"); etPassword.requestFocus(); return; }

        setLoading(true);

        authRepository.login(email, password, new AuthRepository.OnAuthResult() {
            @Override
            public void onSuccess(com.example.medibloomappv2.data.local.entity.UserEntity user) {
                runOnUiThread(() -> {
                    setLoading(false);
                    PreferenceManager prefs = new PreferenceManager(LoginActivity.this);
                    prefs.setUserId(String.valueOf(user.id));
                    prefs.setUserName(user.fullName);
                    prefs.setUserEmail(user.email);
                    goToMain();
                });
            }

            @Override
            public void onFailure(String message) {
                runOnUiThread(() -> {
                    setLoading(false);
                    Toast.makeText(LoginActivity.this, "❌ " + message, Toast.LENGTH_LONG).show();
                });
            }
        });
    }

    private String getFieldText(TextInputEditText et) {
        return et.getText() != null ? et.getText().toString().trim() : "";
    }

    private void setLoading(boolean loading) {
        btnLogin.setEnabled(!loading);
        progressIndicator.setVisibility(loading ? View.VISIBLE : View.GONE);
        btnLogin.setText(loading ? "Logging in…" : "Login");
    }

    private void goToMain() {
        Intent intent = new Intent(this, MainActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        overridePendingTransition(android.R.anim.fade_in, android.R.anim.fade_out);
    }
}

package com.example.medibloomappv2.ui.auth;

import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.example.medibloomappv2.R;
import com.example.medibloomappv2.data.repository.AuthRepository;
import com.example.medibloomappv2.ui.main.MainActivity;
import com.example.medibloomappv2.utils.PreferenceManager;
import com.google.android.material.button.MaterialButton;
import com.google.android.material.progressindicator.CircularProgressIndicator;
import com.google.android.material.textfield.TextInputEditText;

public class LoginActivity extends AppCompatActivity {

    private TextInputEditText etEmail, etPassword;
    private MaterialButton btnLogin;
    private CircularProgressIndicator progressIndicator;
    private AuthRepository authRepository;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        // If the user already has an active session, skip the login screen entirely.
        PreferenceManager prefs = new PreferenceManager(this);
        if (prefs.isLoggedIn()) {
            goToMain();
            return;
        }

        setContentView(R.layout.activity_login);

        authRepository = new AuthRepository(this);

        etEmail = findViewById(R.id.et_email);
        etPassword = findViewById(R.id.et_password);
        btnLogin = findViewById(R.id.btn_login);
        progressIndicator = findViewById(R.id.progress_indicator);
        TextView tvForgotPassword = findViewById(R.id.tv_forgot_password);
        TextView tvSignUp = findViewById(R.id.tv_sign_up);

        btnLogin.setOnClickListener(v -> attemptLogin());

        tvForgotPassword.setOnClickListener(v -> {
            startActivity(new Intent(this, ForgotPasswordActivity.class));
            overridePendingTransition(android.R.anim.slide_in_left, android.R.anim.slide_out_right);
        });

        tvSignUp.setOnClickListener(v -> {
            startActivity(new Intent(this, SignUpActivity.class));
            overridePendingTransition(android.R.anim.slide_in_left, android.R.anim.slide_out_right);
        });
    }

    private void attemptLogin() {
        String email = getFieldText(etEmail);
        String password = getFieldText(etPassword);

        if (email.isEmpty()) { etEmail.setError("Email is required"); etEmail.requestFocus(); return; }
        if (password.isEmpty()) { etPassword.setError("Password is required"); etPassword.requestFocus(); return; }
        if (password.length() < 6) { etPassword.setError("Minimum 6 characters"); etPassword.requestFocus(); return; }

        setLoading(true);

        authRepository.login(email, password, new AuthRepository.OnAuthResult() {
            @Override
            public void onSuccess(com.example.medibloomappv2.data.local.entity.UserEntity user) {
                runOnUiThread(() -> {
                    setLoading(false);
                    PreferenceManager prefs = new PreferenceManager(LoginActivity.this);
                    prefs.setUserId(String.valueOf(user.id));
                    prefs.setUserName(user.fullName);
                    prefs.setUserEmail(user.email);
                    goToMain();
                });
            }

            @Override
            public void onFailure(String message) {
                runOnUiThread(() -> {
                    setLoading(false);
                    Toast.makeText(LoginActivity.this, "❌ " + message, Toast.LENGTH_LONG).show();
                });
            }
        });
    }

    private String getFieldText(TextInputEditText et) {
        return et.getText() != null ? et.getText().toString().trim() : "";
    }

    private void setLoading(boolean loading) {
        btnLogin.setEnabled(!loading);
        progressIndicator.setVisibility(loading ? View.VISIBLE : View.GONE);
        btnLogin.setText(loading ? "Logging in…" : "Login");
    }

    private void goToMain() {
        Intent intent = new Intent(this, MainActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        overridePendingTransition(android.R.anim.fade_in, android.R.anim.fade_out);
        finish();
    }
}

package com.example.medibloomappv2.ui.onboarding;

import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.ImageView;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.core.content.ContextCompat;
import androidx.fragment.app.Fragment;

import com.example.medibloomappv2.R;

public class OnboardingPageFragment extends Fragment {

    private static final String ARG_TITLE = "title";
    private static final String ARG_DESC = "desc";
    private static final String ARG_ICON = "icon";
    private static final String ARG_COLOR = "color";

    public static OnboardingPageFragment newInstance(String title, String desc, int icon, int color) {
        OnboardingPageFragment f = new OnboardingPageFragment();
        Bundle args = new Bundle();
        args.putString(ARG_TITLE, title);
        args.putString(ARG_DESC, desc);
        args.putInt(ARG_ICON, icon);
        args.putInt(ARG_COLOR, color);
        f.setArguments(args);
        return f;
    }

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container,
                             @Nullable Bundle savedInstanceState) {
        View view = inflater.inflate(R.layout.fragment_onboarding_page, container, false);

        Bundle args = getArguments();
        if (args == null) return view;

        View iconCircle = view.findViewById(R.id.icon_circle);
        ImageView ivIcon = view.findViewById(R.id.iv_icon);
        TextView tvTitle = view.findViewById(R.id.tv_title);
        TextView tvDesc = view.findViewById(R.id.tv_description);

        tvTitle.setText(args.getString(ARG_TITLE));
        tvDesc.setText(args.getString(ARG_DESC));
        ivIcon.setImageResource(args.getInt(ARG_ICON));
        iconCircle.setBackgroundTintList(
                ContextCompat.getColorStateList(requireContext(), args.getInt(ARG_COLOR)));

        // Animate icon circle
        iconCircle.setAlpha(0f);
        iconCircle.setScaleX(0.5f);
        iconCircle.setScaleY(0.5f);
        iconCircle.animate()
                .alpha(1f).scaleX(1f).scaleY(1f)
                .setDuration(500).setStartDelay(100).start();

        return view;
    }
}

package com.example.medibloomappv2.ui.onboarding;

import android.os.Bundle;
import android.view.LayoutInflater;
